+<meta charset="UTF-8">
+<meta name="viewport" content="width=device-width, initial-scale=1.0">
+<title>BAZventures — Growth as a Forecast</title>
+<link rel="preconnect" href="https://fonts.googleapis.com">
+<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
+<link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;600;700;800&family=Poppins:wght@300;400;500;600&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet">
+<style>
+*,*::before,*::after { border-radius: 0 !important; }
+.rounded-full, .rounded-full * { border-radius: 9999px !important; }
+:root {
+  --brand: #f2572b; --brand2: #E4B8BF; --ink: #111; --panel: #1A1A1A; --panel2: #2C2C2C;
+  --paper: #f5f1ea; --white: #ffffff; --sand: #E8E4E0; --stone: #B0AAA5;
+  --violet: hsl(270, 85%, 72%); --ease: cubic-bezier(.4,0,.2,1);
+  --font-display: 'Plus Jakarta Sans', ui-sans-serif, sans-serif;
+  --font-sans: 'Poppins', ui-sans-serif, system-ui, sans-serif;
+  --font-mono: 'JetBrains Mono', ui-monospace, monospace;
+}
+html { scroll-behavior: smooth; }
+body { font-family: var(--font-sans); -webkit-font-smoothing: antialiased; background: var(--ink); color: var(--sand); margin: 0; line-height: 1.6; }
+img { max-width: 100%; display: block; }
+a { color: inherit; }
+button { font-family: inherit; }
+
+/* Typography */
+.font-display { font-family: var(--font-display); }
+.font-mono { font-family: var(--font-mono); }
+.text-brand { color: var(--brand); }
+.text-violet { color: var(--violet); }
+.bg-brand { background-color: var(--brand); }
+.bg-paper { background: var(--paper); }
+.bg-ink { background: var(--ink); }
+.bg-panel { background: var(--panel); }
+.bg-panel2 { background: var(--panel2); }
+.bg-white { background: var(--white); }
+.text-ink { color: var(--ink); }
+.text-white { color: #fff; }
+.text-sand { color: var(--sand); }
+.text-stone { color: var(--stone); }
+.uppercase { text-transform: uppercase; }
+.tracking-wide { letter-spacing: .1em; }
+.tracking-wider { letter-spacing: .2em; }
+.leading-tight { line-height: 1.2; }
+.leading-relaxed { line-height: 1.7; }
+.font-medium { font-weight: 500; }
+.font-semibold { font-weight: 600; }
+.font-bold { font-weight: 700; }
+.font-extrabold { font-weight: 800; }
+
+/* Layout */
+.container { max-width: 90rem; margin-left: auto; margin-right: auto; padding-left: 1.5rem; padding-right: 1.5rem; }
+.section { padding-top: 6rem; padding-bottom: 6rem; }
+.section-sm { padding-top: 4rem; padding-bottom: 4rem; }
+@media (min-width: 640px) { .section { padding-top: 8rem; padding-bottom: 8rem; } }
+
+/* Header */
+.site-header { position: fixed; top: 0; left: 0; right: 0; z-index: 50; height: 5rem; transition: background .3s var(--ease), backdrop-filter .3s var(--ease), box-shadow .3s var(--ease); }
+.site-header.is-solid { background: rgba(17,17,17,.72); backdrop-filter: blur(18px) saturate(140%); -webkit-backdrop-filter: blur(18px) saturate(140%); box-shadow: 0 1px 0 rgba(255,255,255,.06); }
+.header-inner { display: flex; align-items: center; justify-content: space-between; height: 100%; }
+.nav-link { position: relative; padding-bottom: 2px; transition: color .25s var(--ease); text-decoration: none; font-size: .75rem; letter-spacing: .15em; text-transform: uppercase; color: rgba(255,255,255,.8); }
+.nav-link::after { content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 2px; background: var(--brand); transition: width .3s var(--ease); }
+.nav-link:hover { color: var(--brand) !important; }
+.nav-link:hover::after { width: 100%; }
+.mobile-toggle { display: none; flex-direction: column; gap: .375rem; background: none; border: 0; padding: .25rem; cursor: pointer; }
+.mobile-toggle span { display: block; width: 1.5rem; height: 2px; background: #fff; transition: all .3s var(--ease); }
+@media (max-width: 767px) { .desktop-nav { display: none; } .mobile-toggle { display: flex; } }
+
+/* Mobile drawer */
+.drawer-scrim { position: fixed; inset: 0; z-index: 40; background: rgba(0,0,0,.6); opacity: 0; pointer-events: none; transition: opacity .4s var(--ease); }
+.drawer-scrim.open { opacity: 1; pointer-events: auto; }
+.mobile-drawer { position: fixed; top: 0; right: -340px; width: 340px; max-width: 80vw; height: 100vh; z-index: 40; background: rgba(17,17,17,.92); backdrop-filter: blur(24px); border-left: 1px solid rgba(255,255,255,.1); padding: 6rem 2rem 2rem; display: flex; flex-direction: column; gap: 1.5rem; transition: right .5s var(--ease); }
+.mobile-drawer.open { right: 0; }
+.mobile-drawer a { font-family: var(--font-display); font-size: .875rem; letter-spacing: .15em; text-transform: uppercase; color: var(--sand); text-decoration: none; transition: color .25s; }
+.mobile-drawer a:hover { color: var(--brand); }
+
+/* Hero */
+.hero { position: relative; min-height: 88vh; display: flex; align-items: center; overflow: hidden; }
+.hero::before { content: ''; position: absolute; inset: 0; background: radial-gradient(circle at 1px 1px, rgba(255,255,255,.12) 1px, transparent 0); background-size: 40px 40px; opacity: .15; pointer-events: none; }
+.hero-inner { position: relative; z-index: 2; max-width: 72rem; margin: 0 auto; padding: 8rem 1.5rem 4rem; width: 100%; }
+.hero-eyebrow { font-family: var(--font-mono); font-size: .6875rem; font-weight: 500; letter-spacing: .35em; text-transform: uppercase; color: var(--brand); display: inline-flex; align-items: center; gap: .5rem; margin-bottom: 1.5rem; }
+.hero-eyebrow::before { content: ''; width: 6px; height: 6px; background: var(--brand); display: inline-block; }
+.hero-title { font-family: var(--font-display); text-transform: uppercase; font-size: clamp(2rem, 6.5vw, 5rem); font-weight: 700; line-height: 1.05; letter-spacing: -.02em; color: #fff; margin: 0 0 1.5rem; }
+.hero-subtitle { font-size: 1.125rem; color: rgba(232,228,224,.85); font-weight: 500; letter-spacing: .04em; max-width: 42rem; margin: 0 0 2rem; }
+@media (min-width: 640px) { .hero-subtitle { font-size: 1.25rem; } }
+
+/* Buttons */
