// Catalog of pi example extensions + curated, conflict-free profiles.
// `key` is the on-disk name under ~/.pi/agent/extensions/ (e.g. "snake.ts" or "plan-mode").
// Extensions sharing a `group` are singletons: only one may be active at a time
// (the orchestrator refuses to enable a second member of the same group).

export type CatalogEntry = {
  key: string;
  desc: string;
  group?: string; // singleton conflict group
  requiresSetup?: boolean; // external deps/config needed -> orchestrator won't auto-enable
  note?: string;
};

export type Profile = {
  desc: string;
  when: string; // when the agent should enable it
  keys: string[]; // example keys to enable
};

